    def __init__(self, input:TokenStream, output:TextIO = sys.stdout):
        super().__init__(input, output)
        self.checkVersion("4.13.0")
        self._interp = ParserATNSimulator(self, self.atn, self.decisionsToDFA, self.sharedContextCache)
        self._predicates = None




    class OwnedExpressionContext(ParserRuleContext):
        __slots__ = 'parser'

        def __init__(self, parser, parent:ParserRuleContext=None, invokingState:int=-1):
            super().__init__(parent, invokingState)
            self.parser = parser

        def IF(self):
            return self.getToken(SysMLv2Parser.IF, 0)

        def ownedExpression(self, i:int=None):
            if i is None:
                return self.getTypedRuleContexts(SysMLv2Parser.OwnedExpressionContext)
            else:
                return self.getTypedRuleContext(SysMLv2Parser.OwnedExpressionContext,i)


